import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import dft from "../../images/default.jpeg";
import Button from "../../components/Button";

const FollowRequest = () => {
  const [User, setUser] = useState({});
  const navigate = useNavigate();

  useEffect(() => {
    const fetchUser = async () => {
      const response = await fetch("http://localhost:8000/api/users", {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${localStorage.getItem("user:token")}`,
        },
      });
      const data = await response.json();
      setUser(data.user);
    };
    fetchUser();
  }, []);

  const handleAccept = async (id) => {
    const response = await fetch("http://localhost:8000/api/accept", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("user:token")}`,
      },
      body: JSON.stringify({ requestedId: id }),
    });
    if (response.status === 200) {
      navigate("/followRequest");
    }
  };

  const handleReject = async (id) => {
    const response = await fetch("http://localhost:8000/api/reject", {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${localStorage.getItem("user:token")}`,
      },
      body: JSON.stringify({ requestedId: id }),
    });
    if (response.status === 200) {
      navigate("/followRequest");
    }
  };

  return (
    <div className="bg-[#dde3f6]">
      <h1 className="font-bold text-[30px] text-center">Follow request</h1>
      <div className="flex flex-col items-center">
        {User?.followRequest?.map(({ _id, profilePic, userName }) => (
          <div key={_id} className="flex border-b cursor-pointer">
            <img
              src={profilePic || dft}
              alt="ProfilePic"
              className="h-[50px] w-[50px] rounded-3xl relative left-[5px]"
            />
            <p className="flex items-center ml-4 text-[25px]">{userName}</p>
            <div className="flex justify-center items-center">
              <Button
                className="mb-4 ml-4 rounded-3xl bg-[#8d91f4] hover:bg-[#525197]"
                label="Accept"
                onChange={() => handleAccept(_id)}
              />
              <Button
                className="mb-4 ml-4 rounded-3xl mr-4 bg-[#8d91f4] hover:bg-[#525197]"
                label="Reject"
                onChange={() => handleReject(_id)}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FollowRequest;
